class TokenBucketRateLimiter:
    """Thread-safe token bucket rate limiter with per-IP tracking."""

    def __init__(self, rate, burst, window):
        self.rate = rate  # tokens per window
        self.burst = burst  # max burst size
        self.window = window
        self.tokens_per_second = rate / window
        self.buckets = {}  # ip -> (tokens, last_refill_time)
        self.lock = threading.Lock()
        # Cleanup old entries periodically
        self._cleanup_interval = 300  # 5 minutes
        self._last_cleanup = time.time()

    def _cleanup_stale_entries(self):
        """Remove entries that haven't been seen in a while."""
        now = time.time()
        if now - self._last_cleanup < self._cleanup_interval:
            return
        stale_threshold = self.window * 2
        stale_keys = [
            ip for ip, (_, last_time) in self.buckets.items()
            if now - last_time > stale_threshold
        ]
        for key in stale_keys:
            del self.buckets[key]
        self._last_cleanup = now

    def is_allowed(self, client_ip):
        """Check if request from client_ip is allowed. Returns (allowed, remaining, retry_after)."""
        with self.lock:
            self._cleanup_stale_entries()
            now = time.time()

            if client_ip not in self.buckets:
                # New client: start with full burst capacity minus 1 for this request
                self.buckets[client_ip] = (self.burst - 1, now)
                return True, self.burst - 1, 0

            tokens, last_refill = self.buckets[client_ip]

            # Refill tokens based on elapsed time
            elapsed = now - last_refill
            new_tokens = elapsed * self.tokens_per_second
            tokens = min(self.burst, tokens + new_tokens)

            if tokens >= 1:
                tokens -= 1
                self.buckets[client_ip] = (tokens, now)
                return True, int(tokens), 0
            else:
                # Calculate when next token will be available
                retry_after = (1 - tokens) / self.tokens_per_second
                self.buckets[client_ip] = (tokens, now)
                return False, 0, round(retry_after, 1)


# Initialize rate limiter
rate_limiter = TokenBucketRateLimiter(
    rate=RATE_LIMIT_REQUESTS,
    burst=RATE_LIMIT_BURST,
    window=RATE_LIMIT_WINDOW,
)


def get_client_ip():
    """Extract client IP, respecting X-Forwarded-For for proxied requests."""
    if request.headers.get("X-Forwarded-For"):
        # Take the first IP (original client)
        return request.headers["X-Forwarded-For"].split(",")[0].strip()
    if request.headers.get("X-Real-IP"):
        return request.headers["X-Real-IP"].strip()
    return request.remote_addr or "unknown"


def rate_limit(f):
    """Rate limiting decorator."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = get_client_ip()
        allowed, remaining, retry_after = rate_limiter.is_allowed(client_ip)

        if not allowed:
            response = jsonify({
                "error": "Rate limit exceeded",
                "message": f"Too many requests. Please retry after {retry_after} seconds.",
                "retry_after": retry_after,
            })
            response.status_code = 429
            response.headers["Retry-After"] = str(retry_after)
            response.headers["X-RateLimit-Limit"] = str(RATE_LIMIT_REQUESTS)
            response.headers["X-RateLimit-Remaining"] = "0"
            response.headers["X-RateLimit-Reset"] = str(int(time.time() + retry_after))
            return response

        # Execute the actual endpoint
        response = f(*args, **kwargs)

        # If response is a tuple (from jsonify, status_code), handle it
        if isinstance(response, tuple):
            resp_obj = response[0]
            status_code = response[1] if len(response) > 1 else 200
            if hasattr(resp_obj, "headers"):
                resp_obj.headers["X-RateLimit-Limit"] = str(RATE_LIMIT_REQUESTS)
                resp_obj.headers["X-RateLimit-Remaining"] = str(remaining)
                resp_obj.headers["X-RateLimit-Reset"] = str(
                    int(time.time() + RATE_LIMIT_WINDOW)
                )
            return resp_obj, status_code
        else:
            if hasattr(response, "headers"):
                response.headers["X-RateLimit-Limit"] = str(RATE_LIMIT_REQUESTS)
                response.headers["X-RateLimit-Remaining"] = str(remaining)
                response.headers["X-RateLimit-Reset"] = str(
                    int(time.time() + RATE_LIMIT_WINDOW)
                )
            return response

    return decorated_function


def build_search_query(keyword, category=None, min_price=None, max_price=None):
    """Build Elasticsearch query for product search."""
    must_clauses = []
    filter_clauses = []

    # Main keyword search across multiple fields with boosting
    must_clauses.append({
        "multi_match": {
            "query": keyword,
            "fields": [
                "name^3",          # Product name gets highest boost
                "description^1.5", # Description gets moderate boost
                "brand^2",         # Brand gets high boost
                "category^1.5",    # Category gets moderate boost
                "tags",            # Tags at normal weight
            ],
            "type": "best_fields",
            "fuzziness": "AUTO",  # Handle typos
            "minimum_should_match": "75%",
        }
    })

    # Optional category filter
    if category:
        filter_clauses.append({"term": {"category.keyword": category}})

    # Optional price range filter
    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range["gte"] = min_price
        if max_price is not None:
            price_range["lte"] = max_price
        filter_clauses.append({"range": {"price": price_range}})

    # Only show available products
    filter_clauses.append({"term": {"available": True}})

    query = {
        "bool": {
            "must": must_clauses,
            "filter": filter_clauses,
        }
    }

    return query


def sanitize_keyword(keyword):
    """Sanitize and validate search keyword."""
    if not keyword:
        return None
    # Strip whitespace and limit length
    keyword = keyword.strip()[:200]
    if len(keyword) < 1:
        return None
    return keyword


@app.route("/api/search", methods=["GET"])
@rate_limit
def search_products():
    """
    Search products by keyword.

    Query Parameters:
        q (str, required): Search keyword
        page (int, optional): Page number (default: 1)
        per_page (int, optional): Results per page (default: 20, max: 100)
        category (str, optional): Filter by category
        min_price (float, optional): Minimum price filter
        max_price (float, optional): Maximum price filter
        sort (str, optional): Sort field - relevance, price_asc, price_desc, newest (default: relevance)

    Returns:
        JSON with search results, pagination info, and metadata.
    """
    # Extract and validate query parameter
    keyword = request.args.get("q", "").strip()
    keyword = sanitize_keyword(keyword)

    if not keyword:
        return jsonify({
            "error": "Missing or invalid search query",
            "message": "Please provide a search keyword using the 'q' parameter.",
        }), 400

    # Pagination parameters
    try:
        page = max(1, int(request.args.get("page", 1)))
    except (ValueError, TypeError):
        page = 1

    try:
        per_page = min(100, max(1, int(request.args.get("per_page", 20))))
    except (ValueError, TypeError):
        per_page = 20

    # Optional filters
    category = request.args.get("category")
    min_price = None
    max_price = None

    try:
        if request.args.get("min_price"):
            min_price = float(request.args["min_price"])
            if min_price < 0:
                min_price = 0
    except (ValueError, TypeError):
        pass

    try:
        if request.args.get("max_price"):
            max_price = float(request.args["max_price"])
            if max_price < 0:
                max_price = None
    except (ValueError, TypeError):
        pass

    # Sorting
    sort_param = request.args.get("sort", "relevance")
    sort_options = {
        "relevance": [{"_score": "desc"}],
        "price_asc": [{"price": "asc"}, {"_score": "desc"}],
        "price_desc": [{"price": "desc"}, {"_score": "desc"}],
        "newest": [{"created_at": "desc"}, {"_score": "desc"}],
    }
    sort = sort_options.get(sort_param, sort_options["relevance"])

    # Build the search query
    search_query = build_search_query(
        keyword=keyword,
        category=category,
        min_price=min_price,
        max_price=max_price,
    )

    # Calculate offset
    from_offset = (page - 1) * per_page

    # Build the full search body
    search_body = {
        "query": search_query,
        "sort": sort,
        "from": from_offset,
        "size": per_page,
        "highlight": {
            "fields": {
                "name": {"number_of_fragments": 1},
                "description": {"number_of_fragments": 2, "fragment_size": 150},
            },
            "pre_tags": ["<em>"],
            "post_tags": ["</em>"],
        },
        "aggs": {
            "categories": {
                "terms": {"field": "category.keyword", "size": 20}
            },
            "price_stats": {
                "stats": {"field": "price"}
            },
            "price_ranges": {
                "range": {
                    "field": "price",
                    "ranges": [
                        {"key": "under_25", "to": 25},
                        {"key": "25_to_50", "from": 25, "to": 50},
                        {"key": "50_to_100", "from": 50, "to": 100},
                        {"key": "100_to_200", "from": 100, "to": 200},
                        {"key": "over_200", "from": 200},
                    ],
                }
            },
        },
        "_source": [
            "name", "description", "price", "category", "brand",
            "image_url", "available", "rating", "review_count",
            "created_at", "sku",
        ],
    }

    # Execute search
    try:
        start_time = time.time()
        response = es.search(index=ES_INDEX, body=search_body)
        search_duration_ms = round((time.time() - start_time) * 1000, 2)
    except Exception as e:
        app.logger.error(f"Elasticsearch error for query '{keyword}': {str(e)}")
        return jsonify({
            "error": "Search service unavailable",
            "message": "We're experiencing issues with our search service. Please try again shortly.",
        }), 503

    # Parse results
    hits = response.get("hits", {})
    total_hits = hits.get("total", {}).get("value", 0)
    total_pages = (total_hits + per_page - 1) // per_page if total_hits > 0 else 0

    products = []
    for hit in hits.get("hits", []):
        product = hit.get("_source", {})
        product["id"] = hit.get("_id")
        product["score"] = hit.get("_score")

        # Include highlights if available
        highlights = hit.get("highlight", {})
        if highlights:
            product["highlights"] = highlights

        products.append(product)

    # Parse aggregations
    aggregations = response.get("aggregations", {})
    facets = {}

    if "categories" in aggregations:
        facets["categories"] = [
            {"name": bucket["key"], "count": bucket["doc_count"]}
            for bucket in aggregations["categories"].get("buckets", [])
        ]

    if "price_stats" in aggregations:
        price_stats = aggregations["price_stats"]
        facets["price_stats"] = {
            "min": price_stats.get("min"),
            "max": price_stats.get("max"),
            "avg": round(price_stats.get("avg", 0), 2) if price_stats.get("avg") else None,
        }

    if "price_ranges" in aggregations:
        facets["price_ranges"] = [
            {"range": bucket["key"], "count": bucket["doc_count"]}
            for bucket in aggregations["price_ranges"].get("buckets", [])
            if bucket["doc_count"] > 0
        ]

    # Build response
    result = {
        "query": keyword,
        "results": products,
        "pagination": {
            "page": page,
            "per_page": per_page,
            "total_results": total_hits,
            "total_pages": total_pages,
            "has_next": page < total_pages,
            "has_prev": page > 1,
        },
        "facets": facets,
        "meta": {
            "search_duration_ms": search_duration_ms,
            "es_took_ms": response.get("took"),
            "sort": sort_param,
            "filters_applied": {
                "category": category,
                "min_price": min_price,
                "max_price": max_price,
            },
        },
    }

    return jsonify(result), 200


@app.route("/api/search/suggest", methods=["GET"])
@rate_limit
def search_suggestions():
    """
    Get search suggestions/autocomplete for a partial query.

    Query Parameters:
        q (str, required): Partial search keyword
        limit (int, optional): Max suggestions (default: 5, max: 10)
    """
    keyword = request.args.get("q", "").strip()
    keyword = sanitize_keyword(keyword)

    if not keyword or len(keyword) < 2:
        return jsonify({"suggestions": []}), 200

    try:
        limit = min(10, max(1, int(request.args.get("limit", 5))))
    except (ValueError, TypeError):
        limit = 5

    suggest_body = {
        "suggest": {
            "product_suggest": {
                "prefix": keyword,
                "completion": {
                    "field": "name_suggest",
                    "size": limit,
                    "skip_duplicates": True,
                    "fuzzy": {
                        "fuzziness": "AUTO",
                    },
                },
            }
        },
        "_source": ["name", "category", "brand"],
    }

    try:
        response = es.search(index=ES_INDEX, body=suggest_body)
    except Exception as e:
        app.logger.error(f"Suggestion error for '{keyword}': {str(e)}")
        return jsonify({"suggestions": []}), 200

    suggestions = []
    suggest_results = response.get("suggest", {}).get("product_suggest", [])
    for suggest in suggest_results:
        for option in suggest.get("options", []):
            source = option.get("_source", {})
            suggestions.append({
                "text": option.get("text", ""),
                "name": source.get("name"),
                "category": source.get("category"),
                "brand": source.get("brand"),
                "score": option.get("_score"),
            })

    return jsonify({"query": keyword, "suggestions": suggestions}), 200


@app.route("/api/health", methods=["GET"])
def health_check():
    """Health check endpoint for load balancers and monitoring."""
    try:
        es_health = es.cluster.health(request_timeout=5)
        es_status = es_health.get("status", "unknown")
        es_healthy = es_status in ("green", "yellow")
    except Exception as e:
        es_healthy = False
        es_status = f"unreachable: {str(e)}"

    status = "healthy" if es_healthy else "degraded"
    status_code = 200 if es_healthy else 503

    return jsonify({
        "status": status,
        "elasticsearch": {
            "status": es_status,
            "healthy": es_healthy,
        },
        "timestamp": time.time(),
    }), status_code


