def create_index_if_not_exists():
    """Create the products index with appropriate mappings if it doesn't exist."""
    if es.indices.exists(index=ES_INDEX):
        return

    mapping = {
        "settings": {
            "number_of_shards": 2,
            "number_of_replicas": 1,
            "analysis": {
                "analyzer": {
                    "product_analyzer": {
                        "type": "custom",
                        "tokenizer": "standard",
                        "filter": ["lowercase", "stop", "snowball"],
                    }
                }
            },
        },
        "mappings": {
            "properties": {
                "name": {
                    "type": "text",
                    "analyzer": "product_analyzer",
                    "fields": {"keyword": {"type": "keyword"}},
                },
                "name_suggest": {
                    "type": "completion",
                    "analyzer": "simple",
                },
                "description": {
                    "type": "text",
                    "analyzer": "product_analyzer",
                },
                "price": {"type": "float"},
                "category": {
                    "type": "text",
                    "fields": {"keyword": {"type": "keyword"}},
                },
                "brand": {
                    "type": "text",
                    "fields": {"keyword": {"type": "keyword"}},
                },
                "tags": {"type": "text"},
                "sku": {"type": "keyword"},
                "image_url": {"type": "keyword", "index": False},
                "available": {"type": "boolean"},
                "rating": {"type": "float"},
                "review_count": {"type": "integer"},
                "created_at": {"type": "date"},
            }
        },
    }

    try:
        es.indices.create(index=ES_INDEX, body=mapping)
        app.logger.info(f"Created index '{ES_INDEX}' with product mappings.")
    except Exception as e:
        app.logger.warning(f"Could not create index '{ES_INDEX}': {str(e)}")


